import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function Signup() {
    const [formData, setFormData] = useState({ name: '', email: '', password: '' });
    const navigate = useNavigate();

    const handleSignup = async (e) => {
        e.preventDefault();
        try {
            await axios.post("http://localhost:5000/api/users/signup", formData);
            alert("Signup Success!");
            navigate('/login');
        } catch (err) {
            alert("Signup Failed!");
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-[#FFFBEB]">
            <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl w-full max-w-md border border-slate-100">
                <h2 className="text-3xl font-black italic uppercase text-center mb-8 text-red-600">Register Pro</h2>
                
                <form onSubmit={handleSignup} className="space-y-4">
                    <input 
                        type="text" 
                        placeholder="Full Name" 
                        className="w-full p-4 bg-slate-50 rounded-2xl border-2 focus:border-red-600 outline-none font-bold"
                        onChange={(e) => setFormData({...formData, name: e.target.value})} 
                        required 
                    />
                    <input 
                        type="email" 
                        placeholder="Email" 
                        className="w-full p-4 bg-slate-50 rounded-2xl border-2 focus:border-red-600 outline-none font-bold"
                        onChange={(e) => setFormData({...formData, email: e.target.value})} 
                        required 
                    />
                    <input 
                        type="password" 
                        placeholder="Password" 
                        className="w-full p-4 bg-slate-50 rounded-2xl border-2 focus:border-red-600 outline-none font-bold"
                        onChange={(e) => setFormData({...formData, password: e.target.value})} 
                        required 
                    />
                    <button className="w-full bg-red-600 text-white py-4 rounded-2xl font-black uppercase hover:bg-slate-900 transition-all shadow-lg">
                        Create Account
                    </button>
                </form>
                
                <p className="text-center mt-6 font-bold text-slate-400 uppercase text-xs">
                    Already have an account? 
                    <span className="text-red-600 cursor-pointer ml-2 hover:underline" onClick={() => navigate('/login')}>Login</span>
                </p>
            </div>
        </div>
    );
}
